#define HSP_FW_DATA_CRAM_SIZE 3707U /*!<  Size of the HSP CRAM buffer to load */


#define HSP_FW_DATA_DRAM_SIZE 3048U /*!<  Size of the HSP DRAM buffer to load */

static const hsp_fw_descriptor_t g_fw_cram_desc =
{
  .p_binary = (const uint8_t *)dataCRAMTab,
  .size_byte = HSP_FW_DATA_CRAM_SIZE * 4U
};

static const hsp_fw_descriptor_t g_fw_dram_desc =
{
  .p_binary = (const uint8_t *)dataDRAMTab,
  .size_byte = HSP_FW_DATA_DRAM_SIZE * 4U
};

const hsp_fw_descriptor_t *hsp_fw_getcram(void)
{
  return &g_fw_cram_desc;
}

const hsp_fw_descriptor_t *hsp_fw_getdram(void)
{
  return &g_fw_dram_desc;
}

